+  using KeyCode = KeyboardHandlerBase::KeyCode;
+/* *INDENT-OFF* */
+  key_code = static_cast<KeyCode>(static_cast<std::underlying_type_t<KeyCode>>(key_code) + 1);
+/* *INDENT-ON* */
+  return key_code;
+}
