+struct termios old_term_settings {};
+
+void quit(int sig)
+{
+  (void)sig;
+  // Restore buffer mode for stdin
+  if (tcsetattr(fileno(stdin), TCSANOW, &old_term_settings) == -1) {
+    exit(EXIT_FAILURE);
+  }
+  exit(EXIT_SUCCESS);
+}
